export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);
  const [userData, setUserData] = useState(null);

  const initializeAuth = useCallback(async () => {
    setLoading(true);
    try {
      await OAuthService.initialize();
      const tokens = await OAuthService.getTokens();
      if (tokens && tokens.accessToken) {
        setAccessToken(tokens.accessToken);
        setRefreshToken(tokens.refreshToken);
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error('Error initializing OAuth:', error);
      Alert.alert('Initialization Error', error.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    initializeAuth();
  }, [initializeAuth]);

  const handleLogin = async () => {
    setLoading(true);
    try {
      const tokens = await OAuthService.login();
      if (tokens) {
        setAccessToken(tokens.accessToken);
        setRefreshToken(tokens.refreshToken);
        setIsAuthenticated(true);
        Alert.alert('Success', 'Logged in successfully!');
      }
    } catch (error) {
      console.error('Login error:', error);
      Alert.alert('Login Failed', error.message || 'An unknown error occurred.');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    setLoading(true);
    try {
      await OAuthService.logout();
      setAccessToken(null);
      setRefreshToken(null);
      setUserData(null);
      setIsAuthenticated(false);
      Alert.alert('Success', 'Logged out successfully!');
    } catch (error) {
      console.error('Logout error:', error);
      Alert.alert('Logout Failed', error.message || 'An unknown error occurred.');
    } finally {
      setLoading(false);
    }
  };

  const handleFetchProtectedData = async () => {
    setLoading(true);
    setUserData(null); // Clear previous data
    try {
      const token = await OAuthService.getAccessToken(); // Ensure we have a valid token (might trigger refresh)
      if (!token) {
        Alert.alert('Error', 'No access token available. Please log in.');
        return;
      }

      // Replace with your actual protected API endpoint
      const response = await fetch('YOUR_PROTECTED_API_ENDPOINT', {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Failed to fetch data: ${response.status} - ${errorText}`);
      }

      const data = await response.json();
      setUserData(data);
      Alert.alert('Success', 'Protected data fetched!');
    } catch (error) {
      console.error('Error fetching protected data:', error);
      Alert.alert('Fetch Error', error.message || 'Could not fetch protected data.');
    } finally {
      setLoading(false);
    }
  };

  const handleRefreshTokenManual = async () => {
    setLoading(true);
    try {
      Alert.alert('Refreshing Token', 'Attempting to refresh the access token...');
      const newTokens = await OAuthService.refreshToken();
      if (newTokens) {
        setAccessToken(newTokens.accessToken);
        setRefreshToken(newTokens.refreshToken);
        Alert.alert('Token Refreshed', 'Access token has been refreshed successfully!');
      } else {
        Alert.alert('Refresh Failed', 'Could not refresh token. Please log in again.');
        setIsAuthenticated(false);
        setAccessToken(null);
        setRefreshToken(null);
      }
    } catch (error) {
      console.error('Manual Refresh Error:', error);
      Alert.alert('Refresh Failed', error.message || 'An error occurred during token refresh.');
      setIsAuthenticated(false); // Force re-login if refresh fails
      setAccessToken(null);
      setRefreshToken(null);
    } finally {
      setLoading(false);
    }
  };

  if (loading && !isAuthenticated) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
        <Text style={styles.statusText}>Loading...</Text>
      </View>
    );
  }

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.title}>OAuth 2.0 Auth Code Flow</Text>
      {isAuthenticated ? (
        <View style={styles.loggedInContainer}>
          <Text style={styles.statusText}>You are logged in!</Text>
          <Text style={styles.tokenLabel}>Access Token:</Text>
          <Text style={styles.tokenValue}>{accessToken ? accessToken.substring(0, 30) + '...' : 'N/A'}</Text>
          <Text style={styles.tokenLabel}>Refresh Token:</Text>
          <Text style={styles.tokenValue}>{refreshToken ? refreshToken.substring(0, 30) + '...' : 'N/A'}</Text>

          <View style={styles.buttonGroup}>
            <Button title="Fetch Protected Data" onPress={handleFetchProtectedData} disabled={loading} />
            <Button title="Manual Refresh Token" onPress={handleRefreshTokenManual} disabled={loading} />
            <Button title="Logout" onPress={handleLogout} color="red" disabled={loading} />
          </View>

          {loading && <ActivityIndicator size="small" color="#0000ff" style={styles.activityIndicator} />}

          {userData && (
            <View style={styles.userDataContainer}>
              <Text style={styles.userDataTitle}>Protected Data:</Text>
              <Text style={styles.userDataContent}>{JSON.stringify(userData, null, 2)}</Text>
            </View>
          )}
        </View>
      ) : (
        <View style={styles.loggedOutContainer}>
          <Text style={styles.statusText}>Please log in to continue.</Text>
          <Button title="Login with OAuth" onPress={handleLogin} disabled={loading} />
          {loading && <ActivityIndicator size="small" color="#0000ff" style={styles.activityIndicator} />}
        </View>
      )}
    </ScrollView>
  );
}

